{
  "sentences": [
    {
      "text": "我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi xiǎo bēi de nátiě, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de na2tie3, ke3yi3 ma0",
      "translation_en": "I would like a small latte, okay?",
      "translation_ko": "작은 사이즈의 라떼 한 잔을 원하는데, 괜찮을까요?"
    },
    {
      "text": "可以幫我加珍珠嗎？",
      "pinyin": "Kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0",
      "translation_en": "Can you add boba for me?",
      "translation_ko": "타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "可以給我半糖的紅茶嗎？",
      "pinyin": "Kěyǐ gěi wǒ bàn táng de hóngchá ma?",
      "pinyin_numeric": "ke3yi3 gei3 wo3 ban4 tang2 de hong2cha2 ma0",
      "translation_en": "Can I have a half-sugar black tea?",
      "translation_ko": "반당 홍차를 주시겠어요?"
    },
    {
      "text": "可以外帶一杯大杯的豆漿嗎？",
      "pinyin": "Kěyǐ wàidài yī bēi dà bēi de dòujiāng ma?",
      "pinyin_numeric": "ke3yi3 wai4dai4 yi1 bei1 da4 bei1 de dou4jiang1 ma0",
      "translation_en": "Can I get a large soy milk to go?",
      "translation_ko": "큰 사이즈 두유 한 잔을 포장해 주시겠어요?"
    },
    {
      "text": "可以給我一杯去冰的綠茶嗎？",
      "pinyin": "Kěyǐ gěi wǒ yī bēi qù bīng de lǜchá ma?",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 bei1 qu4 bing1 de lü4cha2 ma0",
      "translation_en": "Can I have a green tea with no ice?",
      "translation_ko": "�음 없는 녹차 한 잔을 주시겠어요?"
    },
    {
      "text": "可以麻煩你給我一個袋子嗎？",
      "pinyin": "Kěyǐ máfan nǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "ke3yi3 ma2fan5 ni3 gei3 wo3 yi1 ge5 dai4zi5 ma0",
      "translation_en": "Could you please give me a bag?",
      "translation_ko": "봉투 하나를 주시겠어요?"
    },
    {
      "text": "可以幫我拿一根吸管嗎？",
      "pinyin": "Kěyǐ bāng wǒ ná yī gēn xīguǎn ma?",
      "pinyin_numeric": "ke3yi3 bang1 wo3 na2 yi1 gen1 xi1guan3 ma0",
      "translation_en": "Can you get me a straw?",
      "translation_ko": "빨대 하나를 가져다 주시겠어요?"
    },
    {
      "text": "可以給我一個湯匙嗎？",
      "pinyin": "Kěyǐ gěi wǒ yī ge tāngchí ma?",
      "pinyin_numeric": "ke3yi3 gei3 wo3 yi1 ge5 tang1chi2 ma0",
      "translation_en": "Can I have a spoon?",
      "translation_ko": "숟가락 하나를 주시겠어요?"
    },
    {
      "text": "可以請你幫我拍照嗎？",
      "pinyin": "Kěyǐ qǐng nǐ bāng wǒ pāizhào ma?",
      "pinyin_numeric": "ke3yi3 qing3 ni3 bang1 wo3 pai1zhao4 ma0",
      "translation_en": "Can you please take a photo for me?",
      "translation_ko": "사진을 찍어 주시겠어요?"
    },
    {
      "text": "可以等我一下嗎？我先看菜單。",
      "pinyin": "Kěyǐ děng wǒ yīxià ma? Wǒ xiān kàn càidān.",
      "pinyin_numeric": "ke3yi3 deng3 wo3 yi1xia4 ma0? wo3 xian1 kan4 cai4dan1.",
      "translation_en": "Can you wait a moment? I'll look at the menu first.",
      "translation_ko": "잠시만 기다려 주시겠어요? 먼저 메뉴를 볼게요."
    }
  ]
}
